import React from 'react';
import './App.css';

function App() {


    function addNewObject() {
      return <div className="obj"></div>;
    }

    return (
        <div className="app-container">
            <header className="header">
                <h1>🎵 Sound Landscape</h1>
            </header>
            <div className="main">
                <aside className="sidebar">
                    <button onClick={addNewObject}>Добавить объект</button>
                    <button>Удалить объект</button>
                    <button>Выбрать звук</button>
                    <button>Play / Pause</button>
                </aside>
                <div className="canvas-container">
                    {/* Тут будет твоя логика с объектами и Canvas */}
                </div>
            </div>
        </div>
    );
}

export default App;
